package main

import (
	"bytes"
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
)

func proxyHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != "GET" && r.Method != "POST" {
		http.Error(w, "Only GET and POST methods are allowed", http.StatusMethodNotAllowed)
		return
	}

	url := r.URL.Query().Get("url")
	if url == "" {
		http.Error(w, "Missing URL parameter", http.StatusBadRequest)
		return
	}

	resp, err := http.Get(url)
	if err != nil {
		log.Printf("Error fetching content from %s: %v\n", url, err)
		http.Error(w, fmt.Sprintf("Failed to fetch content from %s", url), http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()

	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		log.Printf("Error reading response body for %s: %v\n", url, err)
		http.Error(w, fmt.Sprintf("Failed to read response body from %s", url), http.StatusInternalServerError)
		return
	}

	w.Write(body)
}

func main() {
	http.HandleFunc("/proxy", proxyHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}